import { Registry } from '../core/zc-registry';
import { mathAbs } from '../core/zc-constants';

/**
 *
 * @param num
 * @param base
 * @param allowNonPositive
 * @return {number}
 */
export function logBase(num, base = 10, allowNonPositive = false) {
    const isNegative = num < 0;

    if (allowNonPositive) {
        if (num === 0) {
            return num;
        }
        num = Math.abs(num);
        if (num < base) {
            num += (base - num) / base;
        }
    }

    const result = fixFloatingPoint(Math.log(num) / Math.log(base), 14);
    return isNegative ? -result : result;
}

Registry.setComponent('logUtils.logBase', logBase);

/**
 *
 * @param num
 * @param base
 * @param allowNonPositive
 * @return {number}
 */
export function logArgument(num, base = 10, allowNonPositive = false) {
    const isNegative = num < 0;
    let result = Math.pow(base, num);

    if (allowNonPositive) {
        result = Math.pow(base, Math.abs(num));
        if (result < base) {
            result = (base * (result - 1)) / (base - 1);
        }
        result = isNegative ? -result : result;
    }

    return fixFloatingPoint(result, 12);
}

Registry.setComponent('logUtils.logArgument', logArgument);

/**
 *
 * @param number
 * @param precision
 * @return {number}
 */
export function fixFloatingPoint(number, precision = 14) {
    return parseFloat(number.toPrecision(precision));
}

Registry.setComponent('logUtils.fixFloatingPoint', fixFloatingPoint);

/**
 *
 * @param num
 * @param base
 * @param allowNonPositiveTicks
 * @return {number}
 */
export function getMagnitude(num, base = 10, allowNonPositiveTicks) {
    const isNegative = num < 0;
    if (allowNonPositiveTicks) {
        num = mathAbs(num);
    }

    let exp = Math.floor(logBase(num, base, allowNonPositiveTicks), 14);

    return isNegative ? -Math.pow(base, exp) : Math.pow(base, exp);
}

Registry.setComponent('logUtils.getMagnitude', getMagnitude);
